                    <TouchableOpacity
                        style={styles.buttonSecondary}
                        onPress={() => router.push('/(auth)/login')}
                    >
                        <Text style={styles.buttonTextSecondary}>I already have an account</Text>
                    </TouchableOpacity>
                </Animated.View>
            </View>
        </View>
    );
}

